@RestController
@RequestMapping
class SamlController {

    private final SamlResponseProcessor processor;

    SamlController(SamlResponseProcessor processor) {
        this.processor = processor;
    }

    @PostMapping(value = "/saml/acs", consumes = MediaType.APPLICATION_FORM_URLENCODED_VALUE)
    public void acs(@RequestParam(name = "SAMLResponse", required = false) String samlResponse,
                    @RequestParam(name = "RelayState", required = false) String relayState,
                    HttpServletRequest request,
                    HttpServletResponse response) throws IOException {
        if (!StringUtils.hasText(samlResponse)) {
            response.sendError(400, "Missing SAMLResponse");
            return;
        }

        SamlAuthenticatedSession auth = processor.processSamlResponse(samlResponse);

        HttpSession session = request.getSession(true);
        session.setAttribute(SessionKeys.AUTHENTICATED, Boolean.TRUE);
        session.setAttribute(SessionKeys.USERNAME, auth.getNameId());
        session.setAttribute(SessionKeys.SESSION_INDEX, auth.getSessionIndex());
        session.setAttribute(SessionKeys.ISSUER, auth.getIssuer());
        session.setAttribute(SessionKeys.AUDIENCE, auth.getAudience());
        session.setAttribute(SessionKeys.NOT_ON_OR_AFTER, auth.getNotOnOrAfterEpochSeconds());
        session.setAttribute(SessionKeys.ATTRIBUTES, new HashMap<>(auth.getAttributes()));

        String target = (StringUtils.hasText(relayState) ? relayState : "/");
        if (!target.startsWith("/")) target = "/";
        response.sendRedirect(target);
    }

    @GetMapping("/saml/metadata")
    public String metadata() {
        return """
                <EntityDescriptor xmlns="urn:oasis:names:tc:SAML:2.0:metadata" entityID="urn:example:sp">
                  <SPSSODescriptor AuthnRequestsSigned="false" WantAssertionsSigned="false" protocolSupportEnumeration="urn:oasis:names:tc:SAML:2.0:protocol">
                    <NameIDFormat>urn:oasis:names:tc:SAML:1.1:nameid-format:unspecified</NameIDFormat>
                    <AssertionConsumerService Binding="urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST" Location="/saml/acs" index="0" isDefault="true"/>
                  </SPSSODescriptor>
                </EntityDescriptor>
                """;
    }

    @GetMapping("/me")
    public Map<String, Object> me(HttpServletRequest request) {
        HttpSession session = request.getSession(false);
        Map<String, Object> out = new LinkedHashMap<>();
        if (session == null) {
            out.put("authenticated", false);
            return out;
        }
        out.put("authenticated", Boolean.TRUE.equals(session.getAttribute(SessionKeys.AUTHENTICATED)));
        out.put("username", session.getAttribute(SessionKeys.USERNAME));
        out.put("issuer", session.getAttribute(SessionKeys.ISSUER));
        out.put("audience", session.getAttribute(SessionKeys.AUDIENCE));
        out.put("sessionIndex", session.getAttribute(SessionKeys.SESSION_INDEX));
        out.put("notOnOrAfter", session.getAttribute(SessionKeys.NOT_ON_OR_AFTER));
        Object attrs = session.getAttribute(SessionKeys.ATTRIBUTES);
        out.put("attributes", attrs);
        return out;
    }

    @PostMapping("/logout")
    public void logout(HttpServletRequest request, HttpServletResponse response) throws IOException {
        HttpSession session = request.getSession(false);
        if (session != null) session.invalidate();
        response.sendRedirect("/");
    }
}

@Component
class SamlResponseProcessor {

    private final ReplayCache replayCache = new ReplayCache(10 * 60);

    public SamlAuthenticatedSession processSamlResponse(String samlResponseBase64) {
        String xml = decodeSamlResponse(samlResponseBase64);
        Document doc = parseXmlSecurely(xml);

        Element responseEl = doc.getDocumentElement();
        if (responseEl == null) throw new SamlValidationException("Empty SAML Response");

        String responseId = getAttr(responseEl, "ID");
        if (StringUtils.hasText(responseId)) {
            if (replayCache.seen(responseId)) throw new SamlValidationException("Replay detected");
            replayCache.mark(responseId);
        }

        Element assertion = firstElementByLocalName(responseEl, "Assertion");
        if (assertion == null) {
            Element encryptedAssertion = firstElementByLocalName(responseEl, "EncryptedAssertion");
            if (encryptedAssertion != null) throw new SamlValidationException("EncryptedAssertion not supported in this sample");
            throw new SamlValidationException("Missing Assertion");
        }

        String issuer = textOfFirst(assertion, "Issuer");
        if (!StringUtils.hasText(issuer)) issuer = textOfFirst(responseEl, "Issuer");

        Element subject = firstElementByLocalName(assertion, "Subject");
        String nameId = null;
        if (subject != null) {
            Element nameIdEl = firstElementByLocalName(subject, "NameID");
            if (nameIdEl != null) nameId = normalizeSpace(nameIdEl.getTextContent());
        }
        if (!StringUtils.hasText(nameId)) throw new SamlValidationException("Missing Subject/NameID");

        Element conditions = firstElementByLocalName(assertion, "Conditions");
        String audience = null;
        Long notOnOrAfter = null;
        if (conditions != null) {
            String noa = getAttr(conditions, "NotOnOrAfter");
            if (StringUtils.hasText(noa)) notOnOrAfter = parseInstantEpochSeconds(noa);

            Element audienceRestriction = firstElementByLocalName(conditions, "AudienceRestriction");
            if (audienceRestriction != null) {
                audience = textOfFirst(audienceRestriction, "Audience");
            }
        }

        Element authnStatement = firstElementByLocalName(assertion, "AuthnStatement");
        String sessionIndex = authnStatement != null ? getAttr(authnStatement, "SessionIndex") : null;

        Map<String, List<String>> attributes = extractAttributes(assertion);

        return new SamlAuthenticatedSession(nameId, issuer, audience, sessionIndex, notOnOrAfter, attributes);
    }

    private Map<String, List<String>> extractAttributes(Element assertion) {
        Map<String, List<String>> attrs = new LinkedHashMap<>();
        NodeList attrStatements = assertion.getElementsByTagNameNS("*", "AttributeStatement");
        for (int i = 0; i < attrStatements.getLength(); i++) {
            Node st = attrStatements.item(i);
            if (st.getNodeType() != Node.ELEMENT_NODE) continue;
            NodeList attributes = ((Element) st).getElementsByTagNameNS("*", "Attribute");
            for (int j = 0; j < attributes.getLength(); j++) {
                Node a = attributes.item(j);
                if (a.getNodeType() != Node.ELEMENT_NODE) continue;
                Element attrEl = (Element) a;
                String name = getAttr(attrEl, "Name");
                if (!StringUtils.hasText(name)) name = getAttr(attrEl, "FriendlyName");
                if (!StringUtils.hasText(name)) continue;

                List<String> values = new ArrayList<>();
                NodeList valuesNl = attrEl.getElementsByTagNameNS("*", "AttributeValue");
                for (int k = 0; k < valuesNl.getLength(); k++) {
                    Node v = valuesNl.item(k);
                    if (v.getNodeType() != Node.ELEMENT_NODE) continue;
                    String val = normalizeSpace(v.getTextContent());
                    if (val != null) values.add(val);
                }
                attrs.computeIfAbsent(name, x -> new ArrayList<>()).addAll(values);
            }
        }
        return attrs;
    }

    private String decodeSamlResponse(String samlResponseBase64) {
        byte[] decoded = Base64.getDecoder().decode(samlResponseBase64);
        String xml = new String(decoded, StandardCharsets.UTF_8);
        if (xml.startsWith("<")) return xml;

        try {
            Inflater inflater = new Inflater(true);
            try (InflaterInputStream in = new InflaterInputStream(new ByteArrayInputStream(decoded), inflater)) {
                byte[] buf = in.readAllBytes();
                String inflated = new String(buf, StandardCharsets.UTF_8);
                if (inflated.startsWith("<")) return inflated;
            }
        } catch (Exception ignored) {
        }
        return xml;
    }

    private Document parseXmlSecurely(String xml) {
        try {
            DocumentBuilderFactory dbf = DocumentBuilderFactory.newInstance();
            dbf.setNamespaceAware(true);
            dbf.setFeature(XMLConstants.FEATURE_SECURE_PROCESSING, true);
            dbf.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
            dbf.setFeature("http://xml.org/sax/features/external-general-entities", false);
            dbf.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
            dbf.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false);
            dbf.setXIncludeAware(false);
            dbf.setExpandEntityReferences(false);

            DocumentBuilder db = dbf.newDocumentBuilder();
            InputSource is = new InputSource(new ByteArrayInputStream(xml.getBytes(StandardCharsets.UTF_8)));
            return db.parse(is);
        } catch (Exception e) {
            throw new SamlValidationException("Invalid XML", e);
        }
    }

    private static Element firstElementByLocalName(Element root, String localName) {
        NodeList nl = root.getElementsByTagNameNS("*", localName);
        for (int i = 0; i < nl.getLength(); i++) {
            Node n = nl.item(i);
            if (n.getNodeType() == Node.ELEMENT_NODE) return (Element) n;
        }
        return null;
    }

    private static String textOfFirst(Element root, String localName) {
        Element el = firstElementByLocalName(root, localName);
        if (el == null) return null;
        return normalizeSpace(el.getTextContent());
    }

    private static String getAttr(Element el, String name) {
        if (el == null) return null;
        String v = el.getAttribute(name);
        return StringUtils.hasText(v) ? v : null;
    }

    private static String normalizeSpace(String s) {
        if (s == null) return null;
        String t = s.trim();
        return t.isEmpty() ? null : t.replaceAll("\\s+", " ");
    }

    private static Long parseInstantEpochSeconds(String isoInstant) {
        try {
            return Instant.parse(isoInstant).getEpochSecond();
        } catch (Exception e) {
            return null;
        }
    }
}

@Component
class SamlAuthFilter extends org.springframework.web.filter.OncePerRequestFilter {

    private static final Set<String> ALLOW_PATH_PREFIXES = Set.of(
            "/saml/acs",
            "/saml/metadata",
            "/error",
            "/actuator"
    );

    @Override
    protected void doFilterInternal(HttpServletRequest request, HttpServletResponse response, FilterChain filterChain)
            throws ServletException, IOException {

        String path = request.getRequestURI();
        if (isAllowed(path) || isStaticResource(path)) {
            filterChain.doFilter(request, response);
            return;
        }

        HttpSession session = request.getSession(false);
        boolean authed = session != null && Boolean.TRUE.equals(session.getAttribute(SessionKeys.AUTHENTICATED));
        if (!authed) {
            response.setStatus(401);
            response.setContentType("text/plain; charset=utf-8");
            response.getWriter().write("Unauthorized");
            return;
        }

        Long noa = (Long) session.getAttribute(SessionKeys.NOT_ON_OR_AFTER);
        if (noa != null) {
            long now = Instant.now().getEpochSecond();
            if (now >= noa) {
                session.invalidate();
                response.setStatus(401);
                response.setContentType("text/plain; charset=utf-8");
                response.getWriter().write("Session expired");
                return;
            }
        }

        filterChain.doFilter(request, response);
    }

    private boolean isAllowed(String path) {
        if (path == null) return true;
        for (String p : ALLOW_PATH_PREFIXES) {
            if (path.startsWith(p)) return true;
        }
        return path.equals("/") || path.equals("");
    }

    private boolean isStaticResource(String path) {
        if (path == null) return false;
        return path.startsWith("/css/") || path.startsWith("/js/") || path.startsWith("/images/") || path.startsWith("/webjars/") || path.startsWith("/favicon");
    }
}

final class SessionKeys {
    static final String AUTHENTICATED = "SAML_AUTHENTICATED";
    static final String USERNAME = "SAML_NAMEID";
    static final String ATTRIBUTES = "SAML_ATTRIBUTES";
    static final String SESSION_INDEX = "SAML_SESSION_INDEX";
    static final String ISSUER = "SAML_ISSUER";
    static final String AUDIENCE = "SAML_AUDIENCE";
    static final String NOT_ON_OR_AFTER = "SAML_NOT_ON_OR_AFTER_EPOCH_SECONDS";

    private SessionKeys() {}
}

final class SamlAuthenticatedSession {
    private final String nameId;
    private final String issuer;
    private final String audience;
    private final String sessionIndex;
    private final Long notOnOrAfterEpochSeconds;
    private final Map<String, List<String>> attributes;

    SamlAuthenticatedSession(String nameId,
                             String issuer,
                             String audience,
                             String sessionIndex,
                             Long notOnOrAfterEpochSeconds,
                             Map<String, List<String>> attributes) {
        this.nameId = nameId;
        this.issuer = issuer;
        this.audience = audience;
        this.sessionIndex = sessionIndex;
        this.notOnOrAfterEpochSeconds = notOnOrAfterEpochSeconds;
        this.attributes = attributes == null ? Map.of() : Collections.unmodifiableMap(attributes);
    }

    public String getNameId() { return nameId; }
    public String getIssuer() { return issuer; }
    public String getAudience() { return audience; }
    public String getSessionIndex() { return sessionIndex; }
    public Long getNotOnOrAfterEpochSeconds() { return notOnOrAfterEpochSeconds; }
    public Map<String, List<String>> getAttributes() { return attributes; }
}

